# Extracting prepositional phrases (requires walking the dependency tree)
import spacy

nlp = spacy.load("en_core_web_sm")

def extract_prepositional_phrases(doc):
    """Return all (verb, prep, noun) triples in the document."""
    triples = []
    for token in doc:
        if token.dep_ == "prep" and token.head.pos_ in ("VERB", "NOUN"):
            pobj = [c for c in token.children if c.dep_ == "pobj"]
            for obj in pobj:
                triples.append({
                    "head": token.head.text,
                    "prep": token.text,
                    "object": obj.text,
                    "full_np": " ".join(t.text for t in obj.subtree),
                })
    return triples

doc = nlp("The report was submitted to the board of directors on Monday.")
for triple in extract_prepositional_phrases(doc):
    print(f"  {triple['head']} → {triple['prep']} → {triple['full_np']}")
# submitted → to → the board of directors
# submitted → on → Monday
